<?php defined('BASEPATH') or exit('No direct script access allowed'); ?><?php init_head(); ?><div id="wrapper"><div class="content"><div class="panel_s"><div class="panel-body"><h4><?php echo _l('system_limits_audit_logs'); ?></h4><hr class="hr-panel-heading" /><table class="table dt-table"><thead><tr><th><?php echo _l('date'); ?></th><th><?php echo _l('staff'); ?></th><th><?php echo _l('system_limits_action'); ?></th><th><?php echo _l('system_limits_description'); ?></th></tr></thead><tbody><?php foreach($logs as $log): ?><tr><td><?php echo _dt($log['created_at']); ?></td><td><?php echo (int)$log['staff_id']; ?></td><td><?php echo html_escape($log['action']); ?></td><td><?php echo html_escape($log['description']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div></div><?php init_tail(); ?>
